package com.bankapp.module;

import android.content.Context;
import android.content.SharedPreferences;
import android.os.AsyncTask;
import android.util.Log;
import java.math.BigDecimal;
import java.math.RoundingMode;
import java.security.SecureRandom;
import java.util.concurrent.locks.ReentrantLock;
import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.SecretKeySpec;

public class BankingModule {
    private static final String TAG = "BankingModule";
    private static final String PREFS_NAME = "banking_prefs";
    private static final String BALANCE_KEY = "account_balance";
    private static final String ENCRYPTED_KEY = "encrypted_key";
    private static final String TRANSACTION_HISTORY = "transaction_history";
    
    private Context context;
    private SharedPreferences prefs;
    private ReentrantLock balanceLock = new ReentrantLock();
    private SecretKey secretKey;
    
    public BankingModule(Context context) {
        this.context = context;
        this.prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        this.secretKey = loadOrCreateKey();
    }
    
    private SecretKey loadOrCreateKey() {
        try {
            String encryptedKey = prefs.getString(ENCRYPTED_KEY, null);
            if (encryptedKey != null) {
                byte[] keyBytes = decryptData(encryptedKey);
                return new SecretKeySpec(keyBytes, "AES");
            } else {
                KeyGenerator keyGenerator = KeyGenerator.getInstance("AES");
                keyGenerator.init(256);
                SecretKey key = keyGenerator.generateKey();
                String encrypted = encryptData(key.getEncoded());
                prefs.edit().putString(ENCRYPTED_KEY, encrypted).apply();
                return key;
            }
        } catch (Exception e) {
            Log.e(TAG, "Error loading key", e);
            return null;
        }
    }
    
    public BigDecimal getAccountBalance() {
        balanceLock.lock();
        try {
            String balanceStr = prefs.getString(BALANCE_KEY, "0.00");
            return new BigDecimal(balanceStr).setScale(2, RoundingMode.HALF_UP);
        } catch (NumberFormatException e) {
            Log.e(TAG, "Invalid balance format", e);
            return BigDecimal.ZERO;
        } finally {
            balanceLock.unlock();
        }
    }
    
    public boolean processTransaction(BigDecimal amount, String type, String description) {
        if (amount.compareTo(BigDecimal.ZERO) <= 0) {
            Log.e(TAG, "Invalid transaction amount");
            return false;
        }
        
        balanceLock.lock();
        try {
            BigDecimal currentBalance = getAccountBalance();
            BigDecimal newBalance;
            
            if ("DEBIT".equalsIgnoreCase(type)) {
                newBalance = currentBalance.subtract(amount);
                if (newBalance.compareTo(BigDecimal.ZERO) < 0) {
                    Log.e(TAG, "Insufficient funds");
                    return false;
                }
            } else if ("CREDIT".equalsIgnoreCase(type)) {
                newBalance = currentBalance.add(amount);
            } else {
                Log.e(TAG, "Invalid transaction type");
                return false;
            }
            
            prefs.edit().putString(BALANCE_KEY, newBalance.toString()).apply();
            logTransaction(amount, type, description);
            return true;
        } catch (Exception e) {
            Log.e(TAG, "Transaction processing error", e);
            return false;
        } finally {
            balanceLock.unlock();
        }
    }
    
    private void logTransaction(BigDecimal amount, String type, String description) {
        try {
            String history = prefs.getString(TRANSACTION_HISTORY, "");
            String transaction = String.format("%s|%s|%s|%s", 
                System.currentTimeMillis(), 
                type, 
                amount.toString(), 
                description);
            
            if (history.isEmpty()) {
                prefs.edit().putString(TRANSACTION_HISTORY, transaction).apply();
            } else {
                prefs.edit().putString(TRANSACTION_HISTORY, history + ";" + transaction).apply();
            }
        } catch (Exception e) {
            Log.e(TAG, "Error logging transaction", e);
        }
    }
    
    public String[] getTransactionHistory() {
        String history = prefs.getString(TRANSACTION_HISTORY, "");
        if (history.isEmpty()) {
            return new String[0];
        }
        return history.split(";");
    }
    
    private String encryptData(byte[] data) {
        try {
            Cipher cipher = Cipher.getInstance("AES");
            cipher.init(Cipher.ENCRYPT_MODE, secretKey);
            byte[] encrypted = cipher.doFinal(data);
            return android.util.Base64.encodeToString(encrypted, android.util.Base64.DEFAULT);
        } catch (Exception e) {
            Log.e(TAG, "Encryption error", e);
            return null;
        }
    }
    
    private byte[] decryptData(String encryptedData) {
        try {
            byte[] encryptedBytes = android.util.Base64.decode(encryptedData, android.util.Base64.DEFAULT);
            Cipher cipher = Cipher.getInstance("AES");
            cipher.init(Cipher.DECRYPT_MODE, secretKey);
            return cipher.doFinal(encryptedBytes);
        } catch (Exception e) {
            Log.e(TAG, "Decryption error", e);
            return null;
        }
    }
    
    public class TransactionTask extends AsyncTask<Void, Void, Boolean> {
        private BigDecimal amount;
        private String type;
        private String description;
        private TransactionCallback callback;
        
        public TransactionTask(BigDecimal amount, String type, String description, TransactionCallback callback) {
            this.amount = amount;
            this.type = type;
            this.description = description;
            this.callback = callback;
        }
        
        @Override
        protected Boolean doInBackground(Void... voids) {
            return processTransaction(amount, type, description);
        }
        
        @Override
        protected void onPostExecute(Boolean success) {
            if (callback != null) {
                callback.onTransactionComplete(success);
            }
        }
    }
    
    public interface TransactionCallback {
        void onTransactionComplete(boolean success);
    }
}